// ── STATUS HELPERS ────────────────────────────────────────────────────────────

function getStatusStyle(status: BracketStatus): {
  panelClass: string;
  badgeClass: string;
  label: string;
  score: number;
} {
  switch (status) {
    case "clear":
    case "pass":
    case "out_of_scope":
      return {
        panelClass: "border-emerald-200 bg-emerald-50",
        badgeClass: "text-emerald-700",
        label:      "CLEAR — NO IMMEDIATE ACTION REQUIRED",
        score:      88,
      };
    case "approaching":
      return {
        panelClass: "border-amber-200 bg-amber-50",
        badgeClass: "text-amber-700",
        label:      "APPROACHING — REVIEW NOW",
        score:      65,
      };
    case "trap":
    case "fail":
    case "in_scope":
      return {
        panelClass: "border-red-200 bg-red-50",
        badgeClass: "text-red-700",
        label:      "ACTION REQUIRED — GAPS IDENTIFIED",
        score:      42,
      };
    case "deep_trap":
      return {
        panelClass: "border-red-200 bg-red-50",
        badgeClass: "text-red-700",
        label:      "URGENT — SIGNIFICANT GAPS",
        score:      28,
      };
    case "above_trap":
      return {
        panelClass: "border-blue-200 bg-blue-50",
        badgeClass: "text-blue-700",
        label:      "ABOVE THRESHOLD — DIFFERENT PLANNING NEEDED",
        score:      54,
      };
    case "risk":
    default:
      return {
        panelClass: "border-amber-200 bg-amber-50",
        badgeClass: "text-amber-700",
        label:      "AT RISK — VERIFICATION NEEDED",
        score:      50,
      };
  }
}

// ── TIER ALGORITHM ────────────────────────────────────────────────────────────
// COLE decides the tier — the buyer never chooses in the popup
// Rule: $67 only for SAFE/CLEAR outcomes. ANY risk = $147.

function recommendedTier(
  bracketStatus: BracketStatus,
  assetCost: number | string,
  annualTurnover: number | string,
  readyByJune30: boolean,
): PackTier {
  // assetCost over 20000 OR annualTurnover over 10000000 OR readyByJune30 false → tier2. Otherwise tier1.
    if ((assetCost as number) > 20000 || (annualTurnover as number) > 10000000) return 147;
  // Default: safe = $67, any risk = $147
  return (bracketStatus === "clear" || bracketStatus === "out_of_scope" || bracketStatus === "pass")
    ? 67
    : 147;
}

